424	ngx_http_special_response_handler(ngx_http_request_t *r, ngx_int_t error)
425	{
426	    ngx_uint_t                 i, err;
427	    ngx_http_err_page_t       *err_page;
428	    ngx_http_core_loc_conf_t  *clcf;
429	
430	    ngx_log_debug3(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
431	                   "http special response: %i, \"%V?%V\"",
432	                   error, &r->uri, &r->args);
433	
434	    r->err_status = error;
435	
436	    if (r->keepalive) {
437	        switch (error) {
438	            case NGX_HTTP_BAD_REQUEST:
439	            case NGX_HTTP_REQUEST_ENTITY_TOO_LARGE:
440	            case NGX_HTTP_REQUEST_URI_TOO_LARGE:
441	            case NGX_HTTP_TO_HTTPS:
442	            case NGX_HTTPS_CERT_ERROR:
443	            case NGX_HTTPS_NO_CERT:
444	            case NGX_HTTP_INTERNAL_SERVER_ERROR:
445	            case NGX_HTTP_NOT_IMPLEMENTED:
446	                r->keepalive = 0;
447	        }
448	    }
449	
450	    if (r->lingering_close) {
451	        switch (error) {
452	            case NGX_HTTP_BAD_REQUEST:
453	            case NGX_HTTP_TO_HTTPS:
454	            case NGX_HTTPS_CERT_ERROR:
455	            case NGX_HTTPS_NO_CERT:
456	                r->lingering_close = 0;
457	        }
458	    }
459	
460	    r->headers_out.content_type.len = 0;
461	
462	    clcf = ngx_http_get_module_loc_conf(r, ngx_http_core_module);
463	
464	    if (!r->error_page && clcf->error_pages && r->uri_changes != 0) {
465	
466	        if (clcf->recursive_error_pages == 0) {
467	            r->error_page = 1;
468	        }
469	
470	        err_page = clcf->error_pages->elts;
471	
472	        for (i = 0; i < clcf->error_pages->nelts; i++) {
473	            if (err_page[i].status == error) {
474	                return ngx_http_send_error_page(r, &err_page[i]);
475	            }
476	        }
477	    }
478	
479	    r->expect_tested = 1;
480	
481	    if (ngx_http_discard_request_body(r) != NGX_OK) {
482	        r->keepalive = 0;
483	    }
484	
485	    if (clcf->msie_refresh
486	        && r->headers_in.msie
487	        && (error == NGX_HTTP_MOVED_PERMANENTLY
488	            || error == NGX_HTTP_MOVED_TEMPORARILY))
489	    {
490	        return ngx_http_send_refresh(r);
491	    }
492	
493	    if (error == NGX_HTTP_CREATED) {
494	        /* 201 */
495	        err = 0;
496	
497	    } else if (error == NGX_HTTP_NO_CONTENT) {
498	        /* 204 */
499	        err = 0;
500	
501	    } else if (error >= NGX_HTTP_MOVED_PERMANENTLY
502	               && error < NGX_HTTP_LAST_3XX)
503	    {
504	        /* 3XX */
505	        err = error - NGX_HTTP_MOVED_PERMANENTLY + NGX_HTTP_OFF_3XX;
506	
507	    } else if (error >= NGX_HTTP_BAD_REQUEST
508	               && error < NGX_HTTP_LAST_4XX)
509	    {
510	        /* 4XX */
511	        err = error - NGX_HTTP_BAD_REQUEST + NGX_HTTP_OFF_4XX;
512	
513	    } else if (error >= NGX_HTTP_NGINX_CODES
514	               && error < NGX_HTTP_LAST_5XX)
515	    {
516	        /* 49X, 5XX */
517	        err = error - NGX_HTTP_NGINX_CODES + NGX_HTTP_OFF_5XX;
518	        switch (error) {
519	            case NGX_HTTP_TO_HTTPS:
520	            case NGX_HTTPS_CERT_ERROR:
521	            case NGX_HTTPS_NO_CERT:
522	            case NGX_HTTP_REQUEST_HEADER_TOO_LARGE:
523	                r->err_status = NGX_HTTP_BAD_REQUEST;
524	        }
525	
526	    } else {
527	        /* unknown code, zero body */
528	        err = 0;
529	    }
530	
531	    return ngx_http_send_special_response(r, clcf, err);
532	}
533	
534	
535	ngx_int_t
536	ngx_http_filter_finalize_request(ngx_http_request_t *r, ngx_module_t *m,
